package com.mingalarai import android.content.Context import android.graphics.drawable.GradientDrawable import android.view.View import androidx.core.content.ContextCompat fun View.setGradientBackground(startColor: Int, endColor: Int) { val gradientDrawable = GradientDrawable(GradientDrawable.Orientation.LEFT_RIGHT, intArrayOf(ContextCompat.getColor(context, startColor), ContextCompat.getColor(context, endColor))) background = gradientDrawable }